class UoW:
    def __init__(self):
        self.new = []; self.dirty = []; self.removed = []
    def reg_new(self, o): self.new.append(o)
    def reg_dirty(self, o):
        if o not in self.dirty: self.dirty.append(o)
    def reg_removed(self, o): self.removed.append(o)
    def commit(self):
        print(f'{len(self.new)} yeni, {len(self.dirty)} guncel')
