```python
import time, threading

class WB:
    def __init__(self, fi=5):
        self.c={}; self.db={}; self.p=[]
        t=threading.Thread(target=self._f,args=(fi,),daemon=True); t.start()
    def _f(self,i):
        while True:
            time.sleep(i)
            while self.p: k,v=self.p.pop(0); self.db[k]=v
    def set(self,k,v): self.c[k]=v; self.p.append((k,v))
    def get(self,k): return self.c.get(k)

wb=WB(2)
wb.set('x',1); time.sleep(3); print(wb.db)
```

