import warnings; import functools

def deprecated(replacement=None):
    def dec(f):
        @functools.wraps(f)
        def w(*a,**kw):
            msg = f'{f.__name__} deprecated'
            if replacement: msg += f', {replacement} kullanin'
            warnings.warn(msg, DeprecationWarning, 2)
            return f(*a,**kw)
        return w
    return dec

@deprecated(replacement='new_fn')
def old_fn(x): return x*2

print(old_fn(5))
```

