def bitmask_enum(n):
    for mask in range(1 << n):
        subset = []
        for i in range(n):
            if mask & (1 << i):
                subset.append(i+1)
        print(f'Mask {mask:0{n}b}: {subset}')

bitmask_enum(3)
# 2^3 = 8 kombinasyon
```

O(n!) - N-Queens Counter, algoritma karmasikligi acisindan onemli bir konudur. Dogru analiz edildiginde algoritmalarin performansini anlamak ve karsilastirmak mumkun olur.

Kod Ornegi:
```python
def nqueens_count(n):
    def is_safe(board, row, col):
        for i in range(row):
            if board[i] == col or \
               abs(board[i]-col) == row-i:
                return False
        return True

    def solve(board, row):
        if row == n:
            return 1
        count = 0
        for col in range(n):
            if is_safe(board, row, col):
                board[row] = col
                count += solve(board, row+1)
        return count

    return solve([0]*n, 0)

print(nqueens_count(4))  # 2
print(nqueens_count(8))  # 92, O(n!)
```

