Cozum:
```javascript
// HATALI KOD
const value = 42;
value();  // TypeError: value is not a function

// COZUM
if (typeof value === 'function') {
    value();
} else {
    console.log('value bir fonksiyon degil');
}

// Yaygin bir hata:
const funcs = { greet: () => 'Merhaba' };
const fnName = 'greet';
funcs[fnName]();  // Dogru: 'Merhaba'
