const valid = JSON.parse('{"name": "Ali"}');
console.log(valid.name);

// Guvenli parse
function safeJSONParse(str) {
    try {
        return JSON.parse(str);
    } catch (e) {
        console.error('JSON parse hatasi:', e.message);
        return null;
    }
}

// JSON kurallari:
// - Anahtarlar cift tirnakli olmali
// - String'ler cift tirnakli olmali
// - Son virgul olmamali
// - Yorum satirlari olmamali
