    if (age < 0 || age > 150) {
        throw new IllegalArgumentException("Gecersiz yas: " + age);
    }
}

try {
    validateAge(-5);
} catch (IllegalArgumentException e) {
    System.err.println("Dogrulama hatasi: " + e.getMessage());
}
```

